external_knowledge:
Most popular refers to the names with the highest count in a given year and state; 
The list will include one entry per state; 
Each entry in the list includes the name, its rank, the total count of names in that state and year, and the year recorded.

sql:
SELECT COUNT(*) 
FROM name_records 
WHERE name = 'Helen' AND sex_id = 1;

SELECT name, count
FROM name_records
WHERE rank = 1;

SELECT name
FROM name_trends
WHERE peak_count = (SELECT MAX(peak_count) FROM name_trends);

SELECT name, count
FROM name_records
WHERE state_id = (SELECT state_id FROM states WHERE state_name = 'New Jersey') AND year = 2020;

SELECT SUM(count) AS total_count
FROM name_records
WHERE state_id = (SELECT state_id FROM states WHERE state_name = 'New Jersey') AND year = 2020;

SELECT COUNT(record_id) AS total_names
FROM name_records
WHERE year = 2020 AND state_id = (SELECT state_id FROM states WHERE state_name = 'New Jersey');

SELECT peak_year, peak_count
FROM name_trends
WHERE name = 'Mary';
